// Token validation middleware
function validateBearerToken(req, res, next) {
  try {
    const authHeader = req.headers.authorization;
    
    if (!authHeader) {
      return res.status(401).json({ 
        error: 'unauthorized',
        error_description: 'Missing Authorization header' 
      });
    }

    const parts = authHeader.split(' ');
    
    if (parts.length !== 2) {
      return res.status(401).json({ 
        error: 'invalid_request',
        error_description: 'Invalid Authorization header format' 
      });
    }

    const [scheme, token] = parts;

    if (!/^Bearer$/i.test(scheme)) {
      return res.status(401).json({ 
        error: 'invalid_request',
        error_description: 'Authorization scheme must be Bearer' 
      });
    }

    if (!token || typeof token !== 'string' || token.length === 0) {
      return res.status(401).json({ 
        error: 'invalid_token',
        error_description: 'Token is missing or empty' 
      });
    }

    if (token.length > 8192) {
      return res.status(401).json({ 
        error: 'invalid_token',
        error_description: 'Token exceeds maximum length' 
      });
    }

    const verifyOptions = {
      algorithms: ALLOWED_ALGORITHMS,
      issuer: ALLOWED_ISSUERS,
      audience: ALLOWED_AUDIENCES,
      clockTolerance: 30,
      complete: true
    };

    let decoded;
    try {
      decoded = jwt.verify(token, JWT_PUBLIC_KEY, verifyOptions);
    } catch (err) {
      if (err.name === 'TokenExpiredError') {
        return res.status(401).json({ 
          error: 'invalid_token',
          error_description: 'Token has expired' 
        });
      }
      if (err.name === 'JsonWebTokenError') {
        return res.status(401).json({ 
          error: 'invalid_token',
          error_description: 'Token signature verification failed' 
        });
      }
      if (err.name === 'NotBeforeError') {
        return res.status(401).json({ 
          error: 'invalid_token',
          error_description: 'Token not yet valid' 
        });
      }
      return res.status(401).json({ 
        error: 'invalid_token',
        error_description: 'Token validation failed' 
      });
    }

    const payload = decoded.payload;

    if (!payload.sub || typeof payload.sub !== 'string') {
      return res.status(401).json({ 
        error: 'invalid_token',
        error_description: 'Token missing required subject claim' 
      });
    }

    if (!payload.exp || typeof payload.exp !== 'number') {
      return res.status(401).json({ 
        error: 'invalid_token',
        error_description: 'Token missing required expiration claim' 
      });
    }

    if (!payload.iat || typeof payload.iat !== 'number') {
      return res.status(401).json({ 
        error: 'invalid_token',
        error_description: 'Token missing required issued-at claim' 
      });
    }

    const now = Math.floor(Date.now() / 1000);
    if (payload.exp <= now) {
      return res.status(401).json({ 
        error: 'invalid_token',
        error_description: 'Token has expired' 
      });
    }

    if (payload.iat > now + 60) {
      return res.status(401).json({ 
        error: 'invalid_token',
        error_description: 'Token issued in the future' 
      });
    }

    const scopes = payload.scope ? 
      (typeof payload.scope === 'string' ? payload.scope.split(' ') : payload.scope) : 
      [];

    req.auth = {
      sub: payload.sub,
      scopes: scopes,
      claims: payload
    };

    next();
  } catch (err) {
    console.error('Token validation error:', err.message);
    return res.status(500).json({ 
      error: 'server_error',
      error_description: 'Internal server error during token validation' 
    });
  }
}

function requireScope(...requiredScopes) {
  return (req, res, next) => {
    if (!req.auth || !req.auth.scopes) {
      return res.status(403).json({ 
        error: 'insufficient_scope',
        error_description: 'No scopes present in token' 
      });
    }

    const hasRequiredScope = requiredScopes.some(scope => 
      req.auth.scopes.includes(scope)
    );

    if (!hasRequiredScope) {
      return res.status(403).json({ 
        error: 'insufficient_scope',
        error_description: `Required scope: ${requiredScopes.join(' or ')}`,
        scope: requiredScopes.join(' ')
      });
    }

    next();
  };
}

